import{_ as a,o as t,c as o,a4 as i}from"./chunks/framework.Br660gtV.js";const p=JSON.parse('{"title":"ADR-002: Capability detection as runtime auto-configuration","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-002-capability-auto-config.md","filePath":"reference/decisions/ADR-002-capability-auto-config.md"}'),n={name:"reference/decisions/ADR-002-capability-auto-config.md"};function r(s,e,l,c,d,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-002-capability-detection-as-runtime-auto-configuration" tabindex="-1">ADR-002: Capability detection as runtime auto-configuration <a class="header-anchor" href="#adr-002-capability-detection-as-runtime-auto-configuration" aria-label="Permalink to &quot;ADR-002: Capability detection as runtime auto-configuration&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-02 (capability model &amp; auto-config), RD-03 (capability probe)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Terminals vary enormously in colour depth, glyph support, mouse/keyboard protocols, OSC features, and synchronized-output support. An app cannot hardcode these, and asking the user to configure them is a poor experience. The engine needs one authoritative description of &quot;what can this terminal do&quot; that every subsystem reads.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-per-feature-ad-hoc-checks-at-each-call-site" tabindex="-1">Option A: Per-feature ad-hoc checks at each call site <a class="header-anchor" href="#option-a-per-feature-ad-hoc-checks-at-each-call-site" aria-label="Permalink to &quot;Option A: Per-feature ad-hoc checks at each call site&quot;">​</a></h3><ul><li><strong>Pros</strong>: Simple to start; no central model.</li><li><strong>Cons</strong>: Duplicated, inconsistent detection; impossible to test holistically; no single source of truth.</li></ul><h3 id="option-b-a-resolved-frozen-capabilityprofile-from-layered-detection" tabindex="-1">Option B: A resolved, frozen <code>CapabilityProfile</code> from layered detection <a class="header-anchor" href="#option-b-a-resolved-frozen-capabilityprofile-from-layered-detection" aria-label="Permalink to &quot;Option B: A resolved, frozen `CapabilityProfile` from layered detection&quot;">​</a></h3><ul><li><strong>Pros</strong>: One source of truth; layered (env → static table → bounded live query) with per-field provenance; deterministic and injectable for tests; doubles as zero-config auto-configuration.</li><li><strong>Cons</strong>: Up-front modelling effort; a live-query layer needs a bounded async path.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — <code>resolveCapabilities</code> / <code>resolveCapabilitiesAsync</code> produce a deeply frozen <code>CapabilityProfile</code> that the render and host layers consume.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>A single resolved profile makes terminal adaptation a data concern rather than scattered control flow. Detection is layered and every field records the layer that set it (<code>CapabilityReasons</code>), so behaviour is explainable and testable. Because all inputs (<code>env</code>, <code>platform</code>, <code>TerminalQuery</code>, <code>timeoutMs</code>, <code>override</code>) are injectable, the entire detector is unit-testable without a real terminal, and the same machinery serves as <strong>runtime auto-configuration</strong> — apps adapt with zero configuration. The live query is bounded (<code>timeoutMs</code>) and its responses are untrusted data.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Zero-config terminal adaptation; one source of truth for capabilities.</li><li>Fully testable detection; explainable per-field provenance.</li><li>The probe harness (RD-03) reuses the same model to survey real terminals.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>The async layer-2 path adds a bounded-timeout code path to maintain.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A non-responding terminal must never hang detection — mitigated by the bounded <code>timeoutMs</code> fallback (verified by the RD-10 detection-budget test).</li></ul>',20)])])}const f=a(n,[["render",r]]);export{p as __pageData,f as default};
